import json
import os
import sys
import time
from pathlib import Path
from typing import Dict, Any, Optional

# Constants
RUNTIME_LIMIT_SECONDS = 5 * 3600  # 5 hours in seconds
RUN_SUMMARY_PATH = "artifacts/results/run_summary.json"
RUNTIME_REPORT_PATH = "artifacts/results/runtime_report.json"

def load_run_summary() -> Optional[Dict[str, Any]]:
    """Load the run summary generated by main.py."""
    path = Path(RUN_SUMMARY_PATH)
    if not path.exists():
        print(f"Error: Run summary not found at {RUN_SUMMARY_PATH}")
        return None
    
    try:
        with open(path, 'r', encoding='utf-8') as f:
            return json.load(f)
    except (json.JSONDecodeError, IOError) as e:
        print(f"Error reading run summary: {e}")
        return None

def verify_runtime() -> Dict[str, Any]:
    """
    Verify that the total runtime recorded in run_summary.json 
    is within the 5-hour limit.
    
    Returns a dictionary with:
      - runtime_seconds: float (total runtime)
      - within_limit: bool (True if <= 5 hours)
      - limit_seconds: int (the 5-hour threshold)
      - status: str ('PASS' or 'FAIL')
    """
    summary = load_run_summary()
    
    if summary is None:
        return {
            "runtime_seconds": 0.0,
            "within_limit": False,
            "limit_seconds": RUNTIME_LIMIT_SECONDS,
            "status": "FAIL",
            "error": "Run summary file not found or invalid"
        }

    runtime_seconds = summary.get("runtime_seconds", 0.0)
    
    if not isinstance(runtime_seconds, (int, float)):
        return {
            "runtime_seconds": 0.0,
            "within_limit": False,
            "limit_seconds": RUNTIME_LIMIT_SECONDS,
            "status": "FAIL",
            "error": "runtime_seconds is not a valid number"
        }

    within_limit = runtime_seconds <= RUNTIME_LIMIT_SECONDS
    status = "PASS" if within_limit else "FAIL"

    return {
        "runtime_seconds": float(runtime_seconds),
        "within_limit": within_limit,
        "limit_seconds": RUNTIME_LIMIT_SECONDS,
        "status": status
    }

def write_runtime_report(report: Dict[str, Any]) -> str:
    """Write the runtime report to the artifacts directory."""
    output_path = Path(RUNTIME_REPORT_PATH)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(report, f, indent=2)
    
    return str(output_path)

def main():
    """Main entry point for runtime verification."""
    print("Verifying runtime against 5-hour limit...")
    report = verify_runtime()
    output_path = write_runtime_report(report)
    
    print(f"Runtime: {report['runtime_seconds']:.2f} seconds")
    print(f"Limit: {report['limit_seconds']} seconds")
    print(f"Within limit: {report['within_limit']}")
    print(f"Status: {report['status']}")
    print(f"Report written to: {output_path}")
    
    # Exit with error code if limit exceeded
    if not report['within_limit']:
        sys.exit(1)

if __name__ == "__main__":
    main()